changeSet.sql:
CREATE SCHEMA IF NOT EXISTS communication;
CREATE TABLE IF NOT EXISTS communication.comm_template ( id UUID PRIMARY KEY, template_key VARCHAR(120) NOT NULL, channel VARCHAR(20) NOT NULL, locale VARCHAR(15) NOT NULL, version INTEGER NOT NULL, status VARCHAR(20) NOT NULL, subject_template VARCHAR(500), body_template VARCHAR(4000) NOT NULL, variables_schema VARCHAR(4000) NOT NULL, created_by VARCHAR(100), created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(), CONSTRAINT uq_comm_template_key_channel_locale_version UNIQUE (template_key, channel, locale, version) );
CREATE INDEX IF NOT EXISTS idx_comm_template_key ON communication.comm_template (template_key); CREATE INDEX IF NOT EXISTS idx_comm_template_channel_status ON communication.comm_template (channel, status);
CREATE TABLE IF NOT EXISTS communication.comm_delivery ( id UUID PRIMARY KEY, event_id VARCHAR(120) NOT NULL, correlation_id VARCHAR(120) NOT NULL, event_type VARCHAR(120) NOT NULL, event_version VARCHAR(40) NOT NULL, organization_id VARCHAR(120) NOT NULL, entity_id VARCHAR(120) NOT NULL, template_key VARCHAR(150), channel VARCHAR(20) NOT NULL, recipient VARCHAR(240) NOT NULL, template_version INTEGER, idempotency_key VARCHAR(255) NOT NULL UNIQUE, status VARCHAR(32) NOT NULL, failure_category VARCHAR(32), failure_reason VARCHAR(1000), provider_name VARCHAR(50), provider_reference VARCHAR(200), payload_json VARCHAR(8000) NOT NULL, attempt_count INTEGER NOT NULL DEFAULT 0, next_attempt_at TIMESTAMP WITH TIME ZONE, last_attempt_at TIMESTAMP WITH TIME ZONE, created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW() );
CREATE INDEX IF NOT EXISTS idx_comm_delivery_correlation_created ON communication.comm_delivery (correlation_id, created_at DESC); CREATE INDEX IF NOT EXISTS idx_comm_delivery_event_created ON communication.comm_delivery (event_id, created_at DESC); CREATE INDEX IF NOT EXISTS idx_comm_delivery_status_next_attempt ON communication.comm_delivery (status, next_attempt_at);

changeSet.rollback:
DROP TABLE IF EXISTS communication.comm_delivery;
DROP TABLE IF EXISTS communication.comm_template;
DROP SCHEMA IF EXISTS communication;
